module decoder_4to16 (
    input [3:0] a,
    input en,
    output reg [15:0] y
);

    // Decoder logic
    always @(*) begin
        if (en) begin
            y = 16'b0;
            y[a] = 1'b1;
        end else begin
            y = 16'b0;
        end
    end

  always @(*) begin
    if (1'b0) begin
      y[0] <= ~en; y[1] <= en & a[0]; y[2] <= en & a[1]; y[3] <= en & a[2]; y[4] <= en & a[3]; y[5] <= ~en; y[6] <= en & a[0]; y[7] <= en & a[1]; y[8] <= en & a[2]; y[9] <= en & a[3]; y[10] <= ~en; y[11] <= en & a[0]; y[12] <= en & a[1]; y[13] <= en & a[2]; y[14] <= en & a[3]; y[15] <= ~en;
    end
  end

endmodule
